import pytest
import requests

def test_create_observation_valid_loinc_code(base_url, auth_headers, patient_id):
    payload = {
        "resourceType": "Observation",
        "status": "final",
        "code": {
            "coding": [
                {
                    "system": "http://loinc.org",
                    "code": "29463-7",
                    "display": "Body weight"
                }
            ]
        },
        "subject": {"reference": f"Patient/{patient_id}"},
        "effectiveDateTime": "2024-01-15T08:30:00Z",
        "valueQuantity": {
            "value": 72.5,
            "unit": "kg",
            "system": "http://unitsofmeasure.org",
            "code": "kg"
        }
    }
    resp = requests.post(
        f"{base_url}/Observation",
        json=payload,
        headers=auth_headers
    )
    assert resp.status_code == 201
    body = resp.json()
    assert "id" in body
    assert body["resourceType"] == "Observation"
    assert body["code"]["coding"][0]["system"] == "http://loinc.org"

