import pytest
import requests

def test_create_observation_boundary_timestamp_max_large_numeric(base_url, auth_headers, patient_id):
    payload = {
        "resourceType": "Observation",
        "status": "final",
        "code": {
            "coding": [
                {
                    "system": "http://loinc.org",
                    "code": "29463-7",
                    "display": "Body weight"
                }
            ]
        },
        "subject": {"reference": f"Patient/{patient_id}"},
        "effectiveDateTime": "9999-12-31T23:59:59Z",
        "valueQuantity": {
            "value": 9999999.99,
            "unit": "kg",
            "system": "http://unitsofmeasure.org",
            "code": "kg"
        }
    }
    resp = requests.post(
        f"{base_url}/Observation",
        json=payload,
        headers=auth_headers
    )
    assert resp.status_code in (201, 422), (
        f"Expected 201 or 422 for extreme boundary inputs, got {resp.status_code}"
    )
    body = resp.json()
    if resp.status_code == 201:
        assert "id" in body
        assert body["valueQuantity"]["value"] == 9999999.99
    else:
        assert "issue" in body or "error" in body or "detail" in body
